    "id": 11,
    "slug": "nasa-s-northrop-grumman-crs-24-mission-overview",
    "cat": "Astronomia",
    "catCls": "astronomia",
    "img": "https://www.nasa.gov/wp-content/uploads/2026/04/ntv-ng-crs-24-falcon9-cygnus-overview-2160-dark.png?w=2048",
